// Extract the JSON brief from Gemini's response
// With response_mime_type=application/json, Gemini returns valid JSON in parts[0].text
try {
  const raw = $input.first().json.candidates[0].content.parts[0].text;
  const brief = JSON.parse(raw);
  return [{ json: { output: brief } }];
} catch(e) {
  // Fallback — never crash the pipeline
  return [{ json: { output: {
    resource_type: 'unknown',
    resource_name: 'unknown',
    namespace: 'unknown',
    symptom: 'Parser failed: ' + e.message,
    severity: 'warning',
    status: 'firing',
    summary: 'Alert received — Gemini parser error, manual investigation required',
    kubectl_commands: ['get pods -A', 'get events -A --sort-by=.lastTimestamp'],
    promql_queries: ['up']
  }}}];
}
